for (const chunk of Object.values(bundle)) {
	if (chunk.type !== 'chunk') continue;

	// Construct a mapping from a chunk name to its file name
	chunkNamesToFiles.set(chunk.name, chunk.fileName);
	// Construct a mapping from a chunk file to all the modules it imports
	chunkToDependencies.set(chunk.fileName, [...chunk.imports, ...chunk.dynamicImports]);

	if (chunk.isEntry) {
		// Entry chunks should always be kept around since they are to be imported by the runtime
		entryChunks.push(chunk.fileName);
	}
}

for (let chunk = chunksToWalk.pop(); chunk; chunk = chunksToWalk.pop()) {
	for (const dep of chunkToDependencies.get(chunk) ?? []) {
		// Skip dependencies already flagged, dependencies may be repeated and/or circular
		if (chunkDecisions.has(dep)) continue;

		// A dependency of a module used on the server is also used on the server
		chunkDecisions.set(dep, true);
		// Add the dependency to the stack so its own dependencies are also flagged
		chunksToWalk.push(dep);
	}
}

const verifyResult = await session.skill('triage/verify.md', {
	args: { issueDetails },
	commands: [gh, bgproc, agentBrowser, git, node, npx, pnpm],
	result: v.object({
		verdict: v.pipe(
			v.picklist(['bug', 'intended-behavior', 'unclear']),
			v.description('Whether the reported behavior is a bug, intended behavior, or unclear'),
		),
		confidence: v.pipe(
			v.picklist(['high', 'medium', 'low']),
			v.description('Confidence level in the verdict'),
		),
	}),
});

return {
	...family,
	name,
	// This will be used in CSS font faces. Quotes are added by the CSS renderer if
	// this value contains a space.
	uniqueName: `${name}-${hasher.hashObject(family)}`,
	weights: family.weights ? dedupe(family.weights.map((weight) => weight.toString())) : undefined,
	styles: family.styles ? dedupe(family.styles) : undefined,
	subsets: family.subsets ? dedupe(family.subsets) : undefined,
	formats: family.formats ? dedupe(family.formats) : undefined,
	fallbacks: family.fallbacks ? dedupe(family.fallbacks) : undefined,
	unicodeRange: family.unicodeRange ? dedupe(family.unicodeRange) : undefined,
};

if (isNamedRenderer(renderer)) {
	this.#pipeline.manifest.renderers.push({
		name: renderer.name,
		ssr: renderer,
	});
} else if ('name' in options) {
	this.#pipeline.manifest.renderers.push({
		name: options.name,
		ssr: renderer,
	});
} else {
	throw new Error(
		'The renderer name must be provided when adding a server renderer that is not a named renderer.',
	);
}

if (this.middleware) {
	const middlewareInstance = await this.middleware();
	const onRequest = middlewareInstance.onRequest ?? NOOP_MIDDLEWARE_FN;
	const internalMiddlewares = [onRequest];
	if (this.manifest.checkOrigin) {
		// this middleware must be placed at the beginning because it needs to block incoming requests
		internalMiddlewares.unshift(createOriginCheckMiddleware());
	}
	this.resolvedMiddleware = sequence(...internalMiddlewares);
	return this.resolvedMiddleware;
} else {
	this.resolvedMiddleware = NOOP_MIDDLEWARE_FN;
	return this.resolvedMiddleware;
}

if (key in values) {
	const value = values[key];
	if (value) {
		let decodedValue: string;
		try {
			decodedValue = decode(value);
		} catch (_error) {
			// If decoding fails (e.g., invalid URI sequences), use the original value
			// This aligns with the behavior of the `cookie` package
			decodedValue = value;
		}
		return new AstroCookie(decodedValue);
	}
}

for (const locale of filteredLocales) {
	for (const route of setRoutes) {
		const hasLocaleInRoute = route.route.split('/').includes(locale);
		if (!hasLocaleInRoute) {
			continue;
		}
		const currentRoutes = routesByLocale.get(locale);
		if (currentRoutes) {
			currentRoutes.push(route);
			routesByLocale.set(locale, currentRoutes);
		} else {
			routesByLocale.set(locale, [route]);
		}
		setRoutes.delete(route);
	}
}

for (const [resolvedPath, island] of serverIslandsState.getDiscoveredIslandEntries()) {
	if (serverIslandsState.hasReferenceId(resolvedPath)) continue;
	const referenceId = ctx.emitFile({
		type: 'chunk',
		id: island.specifier,
		importer: island.importer,
		name: island.islandName,
	});
	serverIslandsState.setReferenceId(resolvedPath, referenceId);
}

try {
	url.pathname = validateAndDecodePathname(url.pathname);
} catch (e) {
	// Multi-level encoding (e.g., %2561 → %61) must be rejected, not silently decoded.
	// Let this error propagate so the caller can return a 400 response.
	if (e instanceof MultiLevelEncodingError) {
		throw e;
	}
	// For other decoding failures (truly malformed URLs), fall back gracefully.
	try {
		url.pathname = decodeURI(url.pathname);
	} catch {
		// If even basic decoding fails, return URL as-is
	}
}

const a11y_non_interactive_element_to_interactive_role_exceptions = {
	ul: ['listbox', 'menu', 'menubar', 'radiogroup', 'tablist', 'tree', 'treegrid'],
	ol: ['listbox', 'menu', 'menubar', 'radiogroup', 'tablist', 'tree', 'treegrid'],
	li: ['menuitem', 'option', 'row', 'tab', 'treeitem'],
	table: ['grid'],
	td: ['gridcell'],
	fieldset: ['radiogroup', 'presentation'],
};

if (elementFile) {
	const elementFileWithPosition = elementFile + (elementPosition ? ':' + elementPosition : '');

	tooltip.sections.push({
		content: elementFileWithPosition.slice(
			(window as DevToolbarMetadata).__astro_dev_toolbar__.root.length - 1, // We want to keep the final slash, so minus one.
		),
		clickDescription: 'Click to go to file',
		async clickAction() {
			// NOTE: The path here has to be absolute and without any errors (no double slashes etc)
			// or Vite will silently fail to open the file. Quite annoying.
			await fetch('/__open-in-editor?file=' + encodeURIComponent(elementFileWithPosition));
		},
	});
}

const addPairs = (
	animations: TransitionDirectionalAnimations | Record<string, TransitionAnimationPair>,
	stylesheet: ViewTransitionStyleSheet,
) => {
	for (const [direction, images] of Object.entries(animations) as Entries<typeof animations>) {
		for (const [image, rules] of Object.entries(images) as Entries<
			(typeof animations)[typeof direction]
		>) {
			stylesheet.addAnimationPair(direction, image, rules);
		}
	}
};

if (response.redirected) {
	const redirectedTo = new URL(response.redirected);
	// but do not redirect cross origin
	if (redirectedTo.origin !== preparationEvent.to.origin) {
		preparationEvent.preventDefault();
		return;
	}
	// preserve fragment
	const fragment = preparationEvent.to.hash;
	preparationEvent.to = redirectedTo;
	preparationEvent.to.hash = fragment;
}

if (inBrowser) {
	if (history.state) {
		// Here we reloaded a page with history state
		// (e.g. history navigation from non-transition page or browser reload)
		currentHistoryIndex = history.state.index;
		scrollTo({ left: history.state.scrollX, top: history.state.scrollY });
	} else if (transitionEnabledOnThisPage()) {
		// This page is loaded from the browser address bar or via a link from extern,
		// it needs a state in the history
		history.replaceState({ index: currentHistoryIndex, scrollX, scrollY }, '');
		history.scrollRestoration = 'manual';
	}
}

for (const el of Array.from(document.head.children)) {
	const newEl = persistedHeadElement(el as HTMLElement, doc);
	// If the element exists in the document already, remove it
	// from the new document and leave the current node alone
	if (newEl) {
		newEl.remove();
	} else {
		if (import.meta.env.DEV && el instanceof HTMLStyleElement) {
			// In DEV mode, keep updated Vue scoped styles for later reuse
			const viteDevId = vueScopedStyleId(el);
			viteDevId && knownVueScopedStyles.set(viteDevId, el);
		}
		// If the element does not exist in the new document, remove the element from current the head.
		el.remove();
	}
}

const moduleEntriesForId = isRootFile
		? // "getModulesByFile" pulls from a delayed module cache (fun implementation detail),
			// So we can get up-to-date info on initial server load.
			// Needed for slower CSS preprocessing like Tailwind
			(environment.moduleGraph.getModulesByFile(id) ?? new Set())
		: // For non-root files, we're safe to pull from "getModuleById" based on testing.
			// TODO: Find better invalidation strategy to use "getModuleById" in all cases!
			new Set([environment.moduleGraph.getModuleById(id)]);

if (filename.startsWith('/@fs')) {
	filename = filename.slice('/@fs'.length);
} else if (filename.startsWith('.')) {
	// Handle relative paths (e.g. ./src/components/Foo.astro) by resolving against root.
	// This can occur on certain environments (e.g. Windows + newer Node.js) when a component
	// is imported via a TypeScript path alias and Vite produces a relative virtual module ID.
	const url = new URL(filename, root);
	filename = viteID(url);
} else if (filename.startsWith('/') && !isPathInRoot(filename, fileURLToPath(root))) {
	const url = new URL('.' + filename, root);
	filename = viteID(url);
}

return createComponent({
		async factory(result: any, props: Record<string, any>) {
			const withVariables = mergeConfig(userConfig, { variables: props });
			const config = resolveComponentImports(
				await setupConfig(withVariables, options),
				tagComponentMap,
				nodeComponentMap,
			);

			return renderComponent(result, Renderer.name, Renderer, { stringifiedAst, config }, {});
		},
		propagation: 'self',
	} as any);

if (isSatteriProcessor(processor)) {
	const { createMdxProcessor: createSatteriMdxProcessor } = await import('./satteri/index.js');
	const satteriProcessor = createSatteriMdxProcessor(opts.mdxOptions, processor.options, {
		srcDir: opts.srcDir,
	});
	return {
		async process(content, filePath, frontmatter) {
			const result = await satteriProcessor.process(content, filePath, frontmatter);
			return { code: result.code, map: null, astroMetadata: result.astroMetadata };
		},
	};
}

try {
	// nosemgrep: javascript.lang.security.audit.detect-non-literal-regexp.detect-non-literal-regexp
	// This only validates the generated pattern before handing it to Netlify.
	new RegExp(regexStr);
} catch {
	logger.warn(
		`Could not generate a valid regex from the remotePattern "${JSON.stringify(
			pattern,
		)}". Please check the syntax.`,
	);
	return undefined;
}

try {
		const result = await renderToStaticMarkup.call(this, Component, props, children, {
			// The purpose of check() is just to validate that this is a Solid component and not
			// React, etc. We should render in sync mode which should skip Suspense boundaries
			// or loading resources like external API calls.
			renderStrategy: 'sync' as RenderStrategy,
		});
		html = result.html;
	} catch {}

if (flags.watch) {
	console.info('Watching for changes...');
} else {
	switch (flags.minimumFailingSeverity) {
		case 'error':
			return result.errors > 0;
		case 'warning':
			return result.errors + result.warnings > 0;
		case 'hint':
			return result.errors + result.warnings + result.hints > 0;
		case undefined:
		default:
			return result.errors > 0;
	}
}

for (const { collected, localFonts } of collectedWithLocalFonts) {
	const properties = unifontFontFaceDataToProperties(collected.data);
	const metrics = await fontMetricsResolver.getMetrics(family.name, collected);
	for (const font of localFonts) {
		css += fontMetricsResolver.generateFontFace({
			metrics,
			fallbackMetrics: systemFallbacksProvider.getMetricsForLocalFont(font),
			font,
			name: nameForFont(font),
			properties,
		});
	}
}

for (const { provider } of families) {
	const id = this.idFromProvider({ hasher, provider });

	if (!providers.has(id)) {
		const unifontProvider = this.astroToUnifontProvider(provider, root);
		// Makes sure every font uses the right instance of a given provider
		// if this provider is provided several times with different options
		// We have to mutate the unifont provider name because unifont deduplicates
		// based on the name.
		unifontProvider._name = this.idFromProvider({ hasher, provider });
		providers.set(id, unifontProvider);
	}
}

if (routeIsRedirect(route)) {
	if (route.redirectRoute) {
		// This is a static redirect
		routeToProcess = route.redirectRoute;
	} else {
		// This is an external redirect, so we return a component stub
		return RedirectSinglePageBuiltModule;
	}
} else if (routeIsFallback(route)) {
	// This is an i18n fallback route
	routeToProcess = getFallbackRoute(route, this.manifest.routes);
}

for (const child of children) {
	if (child.type !== 'element') continue;
	nodes.push({
		type: 'paragraph',
		data: { hName: child.tagName, hProperties: child.properties },
		// We are explicitly casting to the expected type here due to the hacky nature of this
		// function which only works with SVG elements.
		children: makeSvgChildNodes(child.children) as unknown as P['children'],
	});
}

if (entry.tag !== 'meta') {
	// The default favicon should be below any extra icons that the user may have set
	// because if several icons are equally appropriate, the last one is used and we
	// want to use the SVG icon when supported.
	if (
		entry.tag === 'link' &&
		entry.attrs &&
		'rel' in entry.attrs &&
		entry.attrs.rel === 'shortcut icon'
	) {
		return 70;
	}
	return 80;
}

if ('link' in item) {
	return linkFromSidebarLinkItem(item, locale);
} else if ('autogenerate' in item) {
	return entriesFromAutogenerateConfig(item, locale, routes);
} else if ('slug' in item) {
	return linkFromInternalSidebarLinkItem(item, locale);
} else {
	const label = pickLang(item.translations, localeToLang(locale)) || item.label;
	return {
		type: 'group',
		label,
		entries: item.items.flatMap((i) => configItemToEntry(i, locale, routes)),
		collapsed: item.collapsed,
		badge: getSidebarBadge(item.badge, locale, label),
	};
}
